/// Create stateless routes for the Bucket module.
///
/// These routes don't require shared state and are simpler to use.
/// Use this when you only need standard CRUD operations.
///
/// # Example
///
/// ```ignore
/// let module = BucketModule::builder().with_database(pool).build()?;
/// let routes = create_stateless_routes(&module);
/// let app = Router::new().merge(routes);
/// ```
pub fn create_stateless_routes(module: &crate::BucketModule) -> Router<()> {
    Router::new()
        .merge(create_bucket_routes(Arc::new(BucketCrudService::new(
            module.bucket_service.clone()
        ))))
        .merge(create_content_hash_routes(Arc::new(ContentHashCrudService::new(
            module.content_hash_service.clone()
        ))))
        .merge(create_conversion_job_routes(Arc::new(ConversionJobCrudService::new(
            module.conversion_job_service.clone()
        ))))
        .merge(create_file_comment_routes(Arc::new(FileCommentCrudService::new(
            module.file_comment_service.clone()
        ))))
        .merge(create_file_lock_routes(Arc::new(FileLockCrudService::new(
            module.file_lock_service.clone()
        ))))
        .merge(create_file_share_routes(Arc::new(FileShareCrudService::new(
            module.file_share_service.clone()
        ))))
        .merge(create_processing_job_routes(Arc::new(ProcessingJobCrudService::new(
            module.processing_job_service.clone()
        ))))
        .merge(create_stored_file_routes(Arc::new(StoredFileCrudService::new(
            module.stored_file_service.clone()
        ))))
        .merge(create_upload_session_routes(Arc::new(UploadSessionCrudService::new(
            module.upload_session_service.clone()
        ))))
        .merge(create_user_quota_routes(Arc::new(UserQuotaCrudService::new(
            module.user_quota_service.clone()
        ))))
}

/// Get all routes (stateless) for the Bucket module.
